import{_ as a,o as d,c as r,a2 as e}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"结单","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/statement.md","filePath":"zh-CN/portfolio-and-statements/statement.md"}'),o={name:"portfolio-and-statements/statement.md"};function h(p,t,l,i,n,s){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="结单" tabindex="-1">结单 <a class="header-anchor" href="#结单" aria-label="Permalink to &quot;结单&quot;">​</a></h1><p>长桥证券在交易后定期向客户发送日结单与月结单，可通过 App 或邮箱查看，支持简体中文、繁体中文、英文三种语言版本。</p><h2 id="发送时间" tabindex="-1">发送时间 <a class="header-anchor" href="#发送时间" aria-label="Permalink to &quot;发送时间&quot;">​</a></h2><p>日结单：产生交易的 2 个交易日内<br> 月结单：下个月的 5 个交易日内</p><h2 id="结单密码" tabindex="-1">结单密码 <a class="header-anchor" href="#结单密码" aria-label="Permalink to &quot;结单密码&quot;">​</a></h2><p>结单为加密 PDF，密码由手机号末 4 位 + 开户证件号末 4 位组成。如忘记密码请联系客服协助确认。</p><h2 id="查询途径" tabindex="-1">查询途径 <a class="header-anchor" href="#查询途径" aria-label="Permalink to &quot;查询途径&quot;">​</a></h2><p>途径一：长桥 App &gt; 资产 &gt; 全部功能 &gt; 结单查询，可按日期和类型选择对应结单查看。</p><p>途径二：前往开户时填写的邮箱下载查看。如需修改邮箱，可进入长桥 App &gt; 我的 &gt; 设置 &gt; 账号管理 &gt; 邮箱 &gt; 修改邮箱，修改成功后下个结单将发送至新邮箱。</p><h2 id="结单语言" tabindex="-1">结单语言 <a class="header-anchor" href="#结单语言" aria-label="Permalink to &quot;结单语言&quot;">​</a></h2><p>默认结单语言与长桥 App 语言设置保持一致，支持简体中文、繁体中文、英文。</p><p>如需获取其他语言版本，可调整 App 语言设置，修改成功后下个结单生效。</p><p>修改路径：长桥 App &gt; 我的 &gt; 设置 &gt; 通用 &gt; 语言设置 &gt; App 语言，保存即可。</p><h2 id="字段解释" tabindex="-1">字段解释 <a class="header-anchor" href="#字段解释" aria-label="Permalink to &quot;字段解释&quot;">​</a></h2><h3 id="账户总览" tabindex="-1">账户总览 <a class="header-anchor" href="#账户总览" aria-label="Permalink to &quot;账户总览&quot;">​</a></h3><p>展示结单日的日终账户概况，金额统一转化为港币展示。</p><table tabindex="0"><thead><tr><th>字段名</th><th>解释</th></tr></thead><tbody><tr><td>资金余额</td><td>现金余额（或欠款），不含余额通，不含新股或基金申购等预扣的在途资金</td></tr><tr><td>市值</td><td>证券总价值 + 基金总价值 + 现金总价值 + 余额通总价值 + 当月未结算净利息 + 当月未结算累计分红</td></tr><tr><td>总资产</td><td>资金余额 + 证券总价值 + 基金总价值 + 余额通总价值 + 当月未结算净利息总价值</td></tr><tr><td>融资金额</td><td>结单日日终的融资余额</td></tr><tr><td>初始保证金要求</td><td>建新仓需要的保证金</td></tr><tr><td>维持保证金要求</td><td>维持持仓需要的保证金</td></tr><tr><td>应追缴保证金</td><td>结单日日终的应追缴保证金金额</td></tr></tbody></table><h3 id="资金详情" tabindex="-1">资金详情 <a class="header-anchor" href="#资金详情" aria-label="Permalink to &quot;资金详情&quot;">​</a></h3><p>分币种展示结单日的资金变动和日终资金详情。</p><p>期末资金余额 = 期初资金余额 + 变更金额<br> 期末资金余额 = 已交收现金 + 待交收现金</p><table tabindex="0"><thead><tr><th>字段名</th><th>解释</th></tr></thead><tbody><tr><td>期初资金余额</td><td>上一账务日日终资金余额</td></tr><tr><td>变更金额</td><td>结单日的资金变动金额</td></tr><tr><td>期末资金余额</td><td>结单日日终资金余额</td></tr><tr><td>已交收现金</td><td>结单日日终已交收的现金汇总</td></tr><tr><td>待交收现金</td><td>结单日日终未交收的现金汇总</td></tr><tr><td>参考汇率</td><td>对港币的参考汇率</td></tr><tr><td>参考港币资金余额</td><td>参考汇率 × 期末资金余额</td></tr></tbody></table><h3 id="投资组合详情" tabindex="-1">投资组合详情 <a class="header-anchor" href="#投资组合详情" aria-label="Permalink to &quot;投资组合详情&quot;">​</a></h3><p>分交易品种、市场、币种展示结单日的持仓变动和日终持仓详情。</p><p>期末持仓 = 期初持仓 + 变更数量<br> 持仓市值 = 期末持仓 × 价格（股票和期权取收盘价，基金取净值）</p><table tabindex="0"><thead><tr><th>字段名</th><th>解释</th></tr></thead><tbody><tr><td>期初持仓</td><td>上一账务日日终持仓数量</td></tr><tr><td>变更数量</td><td>结单日的持仓变动数量</td></tr><tr><td>期末持仓</td><td>结单日日终持仓数量</td></tr><tr><td>价格</td><td>结单日前（含结单日）的最新收盘价或净值</td></tr><tr><td>持仓市值</td><td>期末持仓 × 价格</td></tr><tr><td>维持保证金比例</td><td>维持持仓需要的保证金比例，无则显示 N/A</td></tr><tr><td>维持保证金</td><td>维持持仓需要的保证金</td></tr><tr><td>成本</td><td>摊薄成本</td></tr><tr><td>浮动盈亏</td><td>当前持有仓位的盈亏</td></tr></tbody></table><h3 id="其他章节说明" tabindex="-1">其他章节说明 <a class="header-anchor" href="#其他章节说明" aria-label="Permalink to &quot;其他章节说明&quot;">​</a></h3><p>公司行动：展示公司行动股票详情，包含持股截止日、预计派发日期、涉及股票、摘要、截止股数及预计派发红利等信息。</p><p>股票交易明细：分市场、币种展示结单日因股票交易引起的持仓和资金变动，结单日即交易日期。</p><p>期权交易明细：分市场、币种展示结单日因期权交易引起的持仓和资金变动，结单日 = 交易日期。</p><p>IPO 认购详情：分市场展示因认购资金扣款引起的资金变动，认购资金扣款日期 = 结单日。</p><p>基金交易详情：分基金类型、币种展示基金交易订单，资金和持仓变动同时展示在其他资金变动、其他持仓变动内，确认日期 = 结单日。</p><p>其他资金出入明细：股票交易、期权交易以外的资金变动，发生日期 = 结单日。</p><p>其他持仓出入明细：股票交易、期权交易以外的持仓变动，发生日期 = 结单日。</p><p>冻结资金明细：分币种展示冻结资金明细，包含发生日期、币种、到期日期、金额及备注，发生日期 = 结单日。</p><p>冻结持仓明细：分交易品种、市场展示冻结持仓明细，包含发生日期、持仓项目、到期日期、数量及备注，发生日期 = 结单日。</p><p>融资利息：截止结单日的当月未扣收融资利息，包含融资利率及已减免金额。</p><p>证券组合费：截止结单日的当月未扣收证券组合费，包含费率及当月累计费用。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/portfolio-and-statements">资产与账单</a></li></ul>',39)])])}const u=a(o,[["render",h]]);export{c as __pageData,u as default};
